def _table_partition_to_nested(table_partition: TablePartition) -> TablePartitionNested:
    """Convert flat TablePartition to nested format."""
    attrs = TablePartitionAttributes()
    _populate_table_partition_attrs(attrs, table_partition)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        table_partition,
        _TABLE_PARTITION_REL_FIELDS,
        TablePartitionRelationshipAttributes,
    )
    return TablePartitionNested(
        guid=table_partition.guid,
        type_name=table_partition.type_name,
        status=table_partition.status,
        version=table_partition.version,
        create_time=table_partition.create_time,
        update_time=table_partition.update_time,
        created_by=table_partition.created_by,
        updated_by=table_partition.updated_by,
        classifications=table_partition.classifications,
        classification_names=table_partition.classification_names,
        meanings=table_partition.meanings,
        labels=table_partition.labels,
        business_attributes=table_partition.business_attributes,
        custom_attributes=table_partition.custom_attributes,
        pending_tasks=table_partition.pending_tasks,
        proxy=table_partition.proxy,
        is_incomplete=table_partition.is_incomplete,
        provenance_type=table_partition.provenance_type,
        home_id=table_partition.home_id,
        depth=table_partition.depth,
        immediate_upstream=table_partition.immediate_upstream,
        immediate_downstream=table_partition.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _table_partition_from_nested(nested: TablePartitionNested) -> TablePartition:
    """Convert nested format to flat TablePartition."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else TablePartitionAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _TABLE_PARTITION_REL_FIELDS,
        TablePartitionRelationshipAttributes,
    )
    return TablePartition(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_table_partition_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _table_partition_to_nested_bytes(
    table_partition: TablePartition, serde: Serde
) -> bytes:
    """Convert flat TablePartition to nested JSON bytes."""
    return serde.encode(_table_partition_to_nested(table_partition))


def _table_partition_from_nested_bytes(data: bytes, serde: Serde) -> TablePartition:
    """Convert nested JSON bytes to flat TablePartition."""
    nested = serde.decode(data, TablePartitionNested)
    return _table_partition_from_nested(nested)


